// El Error Trigger entrega toda la info del fallo en $json
const errorData = $input.first().json;

// Extraer datos del error
const mensajeError = errorData.execution?.error?.message
                  || errorData.error?.message
                  || 'Error desconocido';

const nodoFallido  = errorData.execution?.lastNodeExecuted
                  || 'Nodo desconocido';

const workflowName = errorData.workflow?.name
                  || 'Rag Supabase — Principal';

// Intentar recuperar el nombre del archivo del contexto del error
let archivoFallido = 'desconocido';
try {
  const inputData = errorData.execution?.error?.context?.nodeType || '';
  archivoFallido  = errorData.execution?.data?.startData?.destinationNode
                 || errorData.execution?.workflowData?.name
                 || 'desconocido';
} catch (e) {}

const timestamp = new Date().toISOString();

return [{
  json: {
    archivo:       archivoFallido,
    workflow:      workflowName,
    error_mensaje: mensajeError,
    nodo_fallido:  nodoFallido,
    timestamp,
    // Asunto listo para usar en el email
    email_subject: `❌ RAG Ingesta Fallida — ${archivoFallido}`,
    email_body:    `Se produjo un error en el pipeline RAG.\n\nWorkflow: ${workflowName}\nNodo fallido: ${nodoFallido}\nArchivo: ${archivoFallido}\nError: ${mensajeError}\nFecha: ${timestamp}`
  }
}];
